//! live-inference — runs real forward passes against a local .knot file
//! and emits per-layer standing wave compression metrics.
//!
//! Replaces the prior stub that hardcoded paths and printed cosmetic
//! "compression status" without measuring anything. Every metric in the
//! output comes from `pipeline.standing_wave_metrics_get(layer_idx)`
//! after a real forward pass through `NativeLlamaPipeline::forward_one`.
//!
//! Wire format priority: bitwise binary (zero-copy mappable) preferred,
//! JSON line fallback. Both can be emitted simultaneously.
//!
//! Usage:
//!   live-inference \
//!     --knot /tmp/qwen-coder-7b.knot \
//!     --metrics-bin /tmp/standing-wave-metrics.bwmr \
//!     [--metrics-jsonl /tmp/standing-wave-metrics.jsonl] \
//!     --tokens 1,2,3,4,5,6,7,8 \
//!     [--include-warmup]
//!
//! At least one of --metrics-bin / --metrics-jsonl must be provided.
//! When both are set, every record is written to both (binary primary,
//! JSON shadow). Format details: see standing_wave_metrics_format.rs.

use std::env;
use std::fs::OpenOptions;
use std::io::BufWriter;
use std::time::{Instant, SystemTime, UNIX_EPOCH};

use distributed_inference::loader::KnotWeights;
use distributed_inference::standing_wave_metrics_format::{
    BinarySink, JsonSink, MetricsRecord, MetricsSink, TeeSink,
};
use distributed_inference::NativeLlamaPipeline;

struct Args {
    knot_path: String,
    metrics_bin: Option<String>,
    metrics_jsonl: Option<String>,
    tokens: Vec<u32>,
    include_warmup: bool,
}

fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = env::args().collect();
    let mut knot_path: Option<String> = None;
    let mut metrics_bin: Option<String> = None;
    let mut metrics_jsonl: Option<String> = None;
    let mut tokens: Option<Vec<u32>> = None;
    let mut include_warmup = false;

    let mut i = 1;
    while i < argv.len() {
        match argv[i].as_str() {
            "--knot" => {
                i += 1;
                knot_path = Some(argv.get(i).ok_or("--knot needs a value")?.clone());
            }
            "--metrics-bin" => {
                i += 1;
                metrics_bin = Some(argv.get(i).ok_or("--metrics-bin needs a value")?.clone());
            }
            "--metrics-jsonl" => {
                i += 1;
                metrics_jsonl = Some(argv.get(i).ok_or("--metrics-jsonl needs a value")?.clone());
            }
            "--tokens" => {
                i += 1;
                let raw = argv.get(i).ok_or("--tokens needs a value")?;
                let parsed: Vec<u32> = raw
                    .split(',')
                    .map(|s| {
                        s.trim()
                            .parse::<u32>()
                            .map_err(|e| format!("bad token {:?}: {}", s, e))
                    })
                    .collect::<Result<_, _>>()?;
                tokens = Some(parsed);
            }
            "--include-warmup" => include_warmup = true,
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }

    let args = Args {
        knot_path: knot_path.ok_or("--knot is required")?,
        metrics_bin,
        metrics_jsonl,
        tokens: tokens.ok_or("--tokens is required")?,
        include_warmup,
    };
    if args.metrics_bin.is_none() && args.metrics_jsonl.is_none() {
        return Err("at least one of --metrics-bin or --metrics-jsonl is required".to_string());
    }
    Ok(args)
}

fn now_secs() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0)
}

/// Open the requested sinks. Always returns a single boxed sink that
/// writes to whatever combination of binary + JSON the user asked for.
fn open_sink(
    bin_path: Option<&str>,
    json_path: Option<&str>,
) -> Result<Box<dyn MetricsSink>, String> {
    let make_bin = |p: &str| -> Result<BinarySink<BufWriter<std::fs::File>>, String> {
        let f = OpenOptions::new()
            .create(true)
            .append(true)
            .open(p)
            .map_err(|e| format!("open binary sink {}: {}", p, e))?;
        Ok(BinarySink::new(BufWriter::new(f)))
    };
    let make_json = |p: &str| -> Result<JsonSink<BufWriter<std::fs::File>>, String> {
        let f = OpenOptions::new()
            .create(true)
            .append(true)
            .open(p)
            .map_err(|e| format!("open json sink {}: {}", p, e))?;
        Ok(JsonSink::new(BufWriter::new(f)))
    };

    match (bin_path, json_path) {
        (Some(b), Some(j)) => {
            let primary = make_bin(b)?;
            let fallback = make_json(j)?;
            Ok(Box::new(TeeSink { primary, fallback }))
        }
        (Some(b), None) => Ok(Box::new(make_bin(b)?)),
        (None, Some(j)) => Ok(Box::new(make_json(j)?)),
        (None, None) => unreachable!("validated in parse_args"),
    }
}

fn main() -> Result<(), String> {
    let args = parse_args().inspect_err(|_| {
        eprintln!(
            "usage: live-inference --knot PATH (--metrics-bin PATH | --metrics-jsonl PATH | both) \
                                  --tokens IDS [--include-warmup]"
        );
    })?;

    eprintln!("[live-inference] knot={}", args.knot_path);
    if let Some(p) = &args.metrics_bin {
        eprintln!("[live-inference] metrics_bin={} (bitwise BWMR primary)", p);
    }
    if let Some(p) = &args.metrics_jsonl {
        eprintln!("[live-inference] metrics_jsonl={} (json fallback)", p);
    }
    eprintln!("[live-inference] tokens={} ids", args.tokens.len());

    let t0 = Instant::now();
    let knot =
        KnotWeights::load(&args.knot_path).map_err(|e| format!("knot load failed: {:?}", e))?;
    eprintln!(
        "[live-inference] knot loaded in {} ms",
        t0.elapsed().as_millis()
    );

    let t1 = Instant::now();
    let mut pipeline = NativeLlamaPipeline::from_knot(knot, false, 0.8);
    eprintln!(
        "[live-inference] pipeline built in {} ms",
        t1.elapsed().as_millis()
    );

    let hidden_dim = pipeline.hidden_dim();
    let num_layers = pipeline.num_layers();
    eprintln!(
        "[live-inference] config: hidden_dim={} num_layers={}",
        hidden_dim, num_layers
    );

    let mut sink = open_sink(args.metrics_bin.as_deref(), args.metrics_jsonl.as_deref())?;

    let mut total_layer_writes = 0usize;
    let mut total_forward_ms = 0u128;

    for (step, &token) in args.tokens.iter().enumerate() {
        let t_step = Instant::now();
        pipeline
            .forward_one(token as usize, step, false)
            .map_err(|e| format!("forward_one(token={}, step={}): {}", token, step, e))?;
        let step_ms = t_step.elapsed().as_millis();
        total_forward_ms += step_ms;

        if step == 0 && !args.include_warmup {
            eprintln!(
                "[live-inference] step {} (warmup, no metrics): {} ms",
                step, step_ms
            );
            continue;
        }

        let ts = now_secs();
        let mut wrote_any = false;
        for layer_idx in 0..num_layers {
            if let Some(m) = pipeline.standing_wave_metrics_get(layer_idx) {
                let standing_count = (m.compression_ratio * hidden_dim as f32).round() as u32;
                let rec = MetricsRecord {
                    ts,
                    token_step: step as u32,
                    layer_idx: m.layer_idx as u32,
                    hidden_dim: hidden_dim as u32,
                    standing_count,
                    coverage: m.compression_ratio,
                    speedup: m.estimated_speedup,
                    original_bytes: m.original_size_bytes as u64,
                    compressed_bytes: m.compressed_size_bytes as u64,
                    saved_bytes: m.bandwidth_saved_bytes as u64,
                    forward_ms: step_ms as u64,
                };
                sink.write_record(&rec)
                    .map_err(|e| format!("write record: {}", e))?;
                total_layer_writes += 1;
                wrote_any = true;
            }
        }

        eprintln!(
            "[live-inference] step {} forward={} ms layers_with_metrics={}",
            step,
            step_ms,
            if wrote_any {
                "yes"
            } else {
                "none — pipeline did not populate"
            }
        );
    }

    sink.flush().map_err(|e| format!("flush: {}", e))?;

    eprintln!(
        "[live-inference] DONE: {} forward passes, {} ms total, {} metric records written",
        args.tokens.len(),
        total_forward_ms,
        total_layer_writes,
    );

    if total_layer_writes == 0 {
        return Err("no per-layer standing wave metrics were populated. \
             Either the model has no layers, the pipeline did not call \
             extract_and_record_standing_waves, or seq_len was 0."
            .to_string());
    }

    Ok(())
}
